#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    printf("কতগুলো সংখ্যা ইনপুট দিবেন? ");
    scanf("%d", &n);

    int *arr = (int *) malloc(n * sizeof(int)); // মেমোরি বরাদ্দ

    if (arr == NULL) {
        printf("মেমোরি বরাদ্দ ব্যর্থ হয়েছে!\n");
        return 1;
    }

    for (int i = 0; i < n; i++) {
        arr[i] = i * 10;
        printf("%d ", arr[i]);
    }

    free(arr); // ব্যবহার শেষে মেমোরি ফিরিয়ে দেওয়া বাধ্যতামূলক
    return 0;
}
